  ('dietitian-moex-07994', 'dietitian', 'dietitian-moex-099-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '某研究生設計了一份有關甜食攝取與國小學生過動或注意力不集中之問卷，請某家長在不同時間填寫相 同問卷共二次，而所得到的結果一致性不佳。由此可推斷，此問卷之：', '["效度不佳", "信度不佳", "難度較高", "鑑別力大"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:48+00:00", "source_pdf_sha1": "f9268d3fe5e7", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099130", "c": "108", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "099", "exam_name": "099年第二次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、法醫師、聽力師", "original_question_number": 39, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07995', 'dietitian', 'dietitian-moex-099-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '與問卷調查法相比較，下列何者不是訪問調查法的特點？', '["較容易取得較完整的資料，且較能深入了解問題核心", "訪員的態度較易造成誤差", "保密性比較低", "回收率比較低"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:48+00:00", "source_pdf_sha1": "f9268d3fe5e7", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099130", "c": "108", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "099", "exam_name": "099年第二次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、法醫師、聽力師", "original_question_number": 40, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07996', 'dietitian', 'dietitian-moex-099-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '年第一次專門職業及技術人員高等考試社會工作師考試試題 類       科：營養師 甲、申論題部分：（50分） 不必抄題，作答時請將試題題號及答案依照順序寫在申論試卷上，於本試題上作答者，不予計分。 請以藍、黑色鋼筆或原子筆在申論試卷上作答。', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:48+00:00", "source_pdf_sha1": "acd4d9cef281", "answer_pdf_sha1": "49ced308289d", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "109", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "團體膳食設計與管理", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 99, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07997', 'dietitian', 'dietitian-moex-099-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '下列何者不是循環菜單（cyclical menu）的優點？', '["簡化採購", "庫房可以依計畫來準備食材，易於控管庫房貨品", "在工作分配上，每個人工作量可更平均", "只需要設計一套菜單，因此節省時間"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:48+00:00", "source_pdf_sha1": "acd4d9cef281", "answer_pdf_sha1": "49ced308289d", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "109", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "團體膳食設計與管理", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 1, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07998', 'dietitian', 'dietitian-moex-099-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '菜單設計應盡量符合「三低二高」原則，此「三低」是指：', '["低油、低鈉、低膽固醇", "低油、低鈉、低糖", "低油、低糖、低膽固醇", "低糖、低鈉、低膽固醇"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:48+00:00", "source_pdf_sha1": "acd4d9cef281", "answer_pdf_sha1": "49ced308289d", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "109", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "團體膳食設計與管理", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 2, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07999', 'dietitian', 'dietitian-moex-099-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '依照生命期的三大營養素分配，下列何者錯誤？', '["幼兒期：蛋白質10~15%、脂肪25~30%、醣類55~65%", "青春期：蛋白質12~15%、脂肪25~30%、醣類55~63%", "中年期：蛋白質12~15%、脂肪25~30%、醣類55~63%", "老年期：蛋白質10~20%、脂肪20~35%、醣類60~70%"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:48+00:00", "source_pdf_sha1": "acd4d9cef281", "answer_pdf_sha1": "49ced308289d", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "109", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "團體膳食設計與管理", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 3, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08000', 'dietitian', 'dietitian-moex-099-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '健康盒餐供應的熱量卡數有600、700、800、900大卡，為配合教育部提出的「學校午餐內容及營養素基 準」，其中國小4年級到6年級建議盒餐熱量範圍是多少？', '["800~900大卡", "700~800大卡", "600~700大卡", "500~600大卡"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:48+00:00", "source_pdf_sha1": "acd4d9cef281", "answer_pdf_sha1": "49ced308289d", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "109", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "團體膳食設計與管理", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 4, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08001', 'dietitian', 'dietitian-moex-099-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '100人份「標準食譜」建立的目的是在以科學化的管理，掌握數學化的準確度。通常其食譜表格所載明的 資料，下列敘述何者錯誤？', '["食物材料重量為生品購買量", "使用設備", "製作程序", "一人份營養量"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:48+00:00", "source_pdf_sha1": "acd4d9cef281", "answer_pdf_sha1": "49ced308289d", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "109", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "團體膳食設計與管理", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 5, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08002', 'dietitian', 'dietitian-moex-099-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '颱風後蔬菜價格提高，面對已公告的今日菜單，營養師應如何做較為恰當？', '["漲價供應", "用廉價的芽菜類頂替", "維持正常的供應量與價格", "供應時菜量減少"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:48+00:00", "source_pdf_sha1": "acd4d9cef281", "answer_pdf_sha1": "49ced308289d", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "109", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "團體膳食設計與管理", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 6, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08003', 'dietitian', 'dietitian-moex-099-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '食材進貨驗收採用試劑檢驗時，下列何種結果表示食材安全？', '["紫醛試劑檢測鮮魚呈現橘紅色", "雙氧試劑檢測豆干絲呈現黃褐色", "亞硫試劑檢測雞肉呈現紅色", "皂黃試劑檢測鹹魚呈現紫紅色"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:48+00:00", "source_pdf_sha1": "acd4d9cef281", "answer_pdf_sha1": "49ced308289d", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "109", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "團體膳食設計與管理", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 7, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
